args.sparql:
SELECT ?location ?locationLabel WHERE {
  ?location wdt:P131 wd:Q99 .
  ?location wdt:P5181 wd:Q1035785 .
  OPTIONAL { ?location rdfs:label ?locationLabel . FILTER(LANG(?locationLabel) = "en") }
}

SELECT ?location ?locationLabel WHERE {
  ?location rdfs:label ?label .
  FILTER(LANG(?label) = "en")
  FILTER(REGEX(?label, "sequoi[oa]", "i"))
  ?location wdt:P131 wd:Q99 .  # Located in California
  OPTIONAL { ?location rdfs:label ?locationLabel . FILTER(LANG(?locationLabel) = "en") }
}

SELECT ?location ?locationLabel WHERE {
  ?location wdt:P31/wdt:P279* wd:Q46899055 ;
          wdt:P131 wd:Q99 ;
          rdfs:label ?locationLabel .
  FILTER(LANG(?locationLabel) = "en")
  FILTER(REGEX(?locationLabel, "sequoia|giant|kings canyon", "i"))
} ORDER BY ?locationLabel
